    assert.ok(/r\.ok === true \? ('✓'|'\\u2713')/.test(preflightSrc), 'Should use checkmark for ok');
    assert.ok(preflightSrc.includes("r.ok === 'warn' ? '!'"), 'Should use ! for warn');
    assert.ok(/'(✗|\\u2717)'/.test(preflightSrc), 'Should use X mark for fail');
