// ─── W-mnytn469wx90: Agent busy reassignment ───────────────────────────────

async function testAgentBusyReassignment() {
  console.log('\n── Agent Busy Reassignment ──');

  const engineSrc = fs.readFileSync(path.join(MINIONS_DIR, 'engine.js'), 'utf8');
  const sharedSrc = fs.readFileSync(path.join(MINIONS_DIR, 'engine', 'shared.js'), 'utf8');

  // 1. ENGINE_DEFAULTS has agentBusyReassignMs
  await test('ENGINE_DEFAULTS.agentBusyReassignMs exists and is 600000', () => {
    assert.ok(shared.ENGINE_DEFAULTS.agentBusyReassignMs !== undefined,
      'Missing ENGINE_DEFAULTS.agentBusyReassignMs');
    assert.strictEqual(shared.ENGINE_DEFAULTS.agentBusyReassignMs, 600000,
      'agentBusyReassignMs should default to 600000 (10 min)');
  });

  // 2. _agentBusySince is set when skipReason is agent_busy
  await test('_agentBusySince timestamp set when skipReason is agent_busy', () => {
    assert.ok(engineSrc.includes('_agentBusySince'),
      'engine.js must track _agentBusySince on pending dispatch entries');
    // Should set it only when not already set
    assert.ok(engineSrc.includes("!item._agentBusySince") || engineSrc.includes('!item._agentBusySince'),
      'Should only set _agentBusySince when not already set');
  });

  // 3. _agentBusySince is cleared when reason changes from agent_busy
  await test('_agentBusySince cleared when skipReason changes from agent_busy', () => {
    assert.ok(engineSrc.includes('delete item._agentBusySince'),
      'Must clear _agentBusySince when item is no longer blocked on busy agent');
  });

  // 4. Dispatch loop checks _agentBusySince threshold for reassignment
  await test('dispatch loop checks agentBusyReassignMs threshold for reassignment', () => {
    assert.ok(engineSrc.includes('agentBusyReassignMs'),
      'Dispatch loop should reference agentBusyReassignMs config');
    assert.ok(engineSrc.includes('Reassigning'),
      'Should log a message when reassignment occurs');
  });

  // 5. Reassignment skips explicitly assigned items
  await test('reassignment skips explicitly assigned items', () => {
    // Items with meta.item.agent are explicitly assigned — should not be reassigned
    assert.ok(engineSrc.includes('meta?.item?.agent') || engineSrc.includes("meta?.item?.agent"),
      'Dispatch loop should check for explicit agent assignment');
  });

  // 6. Behavioral: item stays on busy agent below threshold
  await test('item stays on busy agent below threshold (behavioral)', () => {
    const { sanitizeBranch } = shared;
    const now = Date.now();
    const reassignMs = shared.ENGINE_DEFAULTS.agentBusyReassignMs;

    const active = [
      { id: 'dallas-impl-1', agent: 'dallas', meta: { branch: 'work/P-active' } },
    ];
    const pending = [
      {
        id: 'ralph-fix-1', agent: 'dallas', type: 'fix',
        meta: { item: {}, branch: 'work/P-fix' },
        _agentBusySince: new Date(now - (reassignMs / 2)).toISOString(), // half threshold — below
      },
    ];

    const busyAgents = new Set(active.map(d => d.agent));
    const toDispatch = [];

    for (const item of pending) {
      if (busyAgents.has(item.agent)) {
        // Simulate reassignment check: below threshold → skip
        const busySince = item._agentBusySince ? new Date(item._agentBusySince).getTime() : null;
        if (busySince && (now - busySince) > reassignMs) {
          toDispatch.push(item); // would reassign
        }
        // else: stays pending (not reassigned)
        continue;
      }
      toDispatch.push(item);
    }

    assert.strictEqual(toDispatch.length, 0, 'Item should NOT be dispatched/reassigned below threshold');
  });

  // 7. Behavioral: item reassigned above threshold
  await test('item reassigned to alternative agent above threshold (behavioral)', () => {
    const now = Date.now();
    const reassignMs = shared.ENGINE_DEFAULTS.agentBusyReassignMs;

    const active = [
      { id: 'dallas-impl-1', agent: 'dallas', meta: { branch: 'work/P-active' } },
    ];
    const pending = [
      {
        id: 'ralph-fix-1', agent: 'dallas', type: 'fix',
        meta: { item: {}, branch: 'work/P-fix' },
        _agentBusySince: new Date(now - (reassignMs + 60000)).toISOString(), // above threshold
      },
    ];

    const busyAgents = new Set(active.map(d => d.agent));
    const availableAgents = ['ralph', 'ripley', 'lambert'];
    const toDispatch = [];

    for (const item of pending) {
      if (busyAgents.has(item.agent)) {
        const busySince = item._agentBusySince ? new Date(item._agentBusySince).getTime() : null;
        if (busySince && (now - busySince) > reassignMs) {
          // Find alternative agent
          const altAgent = availableAgents.find(a => !busyAgents.has(a));
          if (altAgent) {
            item.agent = altAgent;
            delete item._agentBusySince;
            toDispatch.push(item);
            busyAgents.add(altAgent);
            continue;
          }
        }
        continue;
      }
      toDispatch.push(item);
    }

    assert.strictEqual(toDispatch.length, 1, 'Item should be dispatched after reassignment');
    assert.notStrictEqual(toDispatch[0].agent, 'dallas', 'Should not be assigned to original busy agent');
    assert.ok(availableAgents.includes(toDispatch[0].agent), 'Should be assigned to an available agent');
    assert.strictEqual(toDispatch[0]._agentBusySince, undefined, '_agentBusySince should be cleared after reassignment');
  });

  // 8. Behavioral: explicitly assigned items are NOT reassigned even above threshold
  await test('explicitly assigned items are NOT reassigned (behavioral)', () => {
    const now = Date.now();
    const reassignMs = shared.ENGINE_DEFAULTS.agentBusyReassignMs;

    const active = [
      { id: 'dallas-impl-1', agent: 'dallas', meta: { branch: 'work/P-active' } },
    ];
    const pending = [
      {
        id: 'fix-explicit', agent: 'dallas', type: 'fix',
        meta: { item: { agent: 'dallas' }, branch: 'work/P-explicit' },
        _agentBusySince: new Date(now - (reassignMs + 60000)).toISOString(),
      },
    ];

    const busyAgents = new Set(active.map(d => d.agent));
    const toDispatch = [];

    for (const item of pending) {
      if (busyAgents.has(item.agent)) {
        const isExplicit = !!item.meta?.item?.agent;
        if (isExplicit) { continue; } // explicit items skip reassignment
        const busySince = item._agentBusySince ? new Date(item._agentBusySince).getTime() : null;
        if (busySince && (now - busySince) > reassignMs) {
          item.agent = 'ralph';
          toDispatch.push(item);
          continue;
        }
        continue;
      }
      toDispatch.push(item);
    }

    assert.strictEqual(toDispatch.length, 0, 'Explicitly assigned item should NOT be reassigned');
  });

  // 9. Source code: reassignment uses resolveAgent for routing-aware selection
  await test('reassignment uses resolveAgent for routing-aware agent selection', () => {
    assert.ok(engineSrc.includes('resolveAgent(item.type'),
      'Reassignment should use resolveAgent to find alternative agent via routing table');
  });

  // 10. Source code: reassignment persists agent change to dispatch.json
  await test('reassignment persists agent change to dispatch.json via mutateDispatch', () => {
    // The reassignment must update dispatch.json so the change survives across ticks
    assert.ok(engineSrc.includes('mutateDispatch'),
      'Reassignment must persist via mutateDispatch');
  });

  // 11. Behavioral: temp agent fallback when no idle agent available
  await test('reassignment falls back to temp agents if allowTempAgents enabled (source check)', () => {
    // resolveAgent already handles temp agent creation when allowTempAgents is true.
    // The reassignment path calls resolveAgent which handles this automatically.
    const routingSrc = fs.readFileSync(path.join(MINIONS_DIR, 'engine', 'routing.js'), 'utf8');
    assert.ok(routingSrc.includes('allowTempAgents'),
      'resolveAgent must support temp agent fallback when all permanent agents busy');
  });

  // 12. _agentBusySince annotation only in agent_busy path
  await test('_agentBusySince set only in agent_busy annotation path', () => {
    // Must be set when reason === 'agent_busy' and cleared otherwise
    assert.ok(engineSrc.includes("agent_busy") && engineSrc.includes('_agentBusySince'),
      'Both agent_busy and _agentBusySince should be present in the annotation logic');
  });
}

// ─── #1206: Undefined-agent guard in pending dispatch loop ─────────────────
//
// A pending dispatch item with `item.agent === undefined` must not be handed to
// spawnAgent — it crashes with `TypeError: The "path" argument must be of type
// string. Received undefined`, returns null, and the item stays pending, which
// re-enters the loop on the next tick. Infinite crash loop.

async function testUndefinedAgentGuard() {
  console.log('\n── #1206: Undefined-agent guard in pending dispatch ──');

  const engineSrc = fs.readFileSync(path.join(MINIONS_DIR, 'engine.js'), 'utf8');

  // 1. Source: a truthy guard on item.agent exists in the pending dispatch loop
  await test('engine.js guards against undefined item.agent before toDispatch.push', () => {
    // Must contain a check that item.agent is truthy before dispatch
    // Accept either `if (!item.agent)` style or `typeof item.agent !== 'string'`
    const hasNullishGuard = /if\s*\(\s*!item\.agent\b/.test(engineSrc)
      || /typeof\s+item\.agent\s*!==\s*['"]string['"]/.test(engineSrc);
    assert.ok(hasNullishGuard,
      'engine.js must include a guard on item.agent being nullish/non-string before spawn');
  });

  // 2. Source: the guard uses resolveAgent() with the item type as fallback
  await test('undefined-agent guard uses resolveAgent for fallback resolution', () => {
    // The guard block should reference resolveAgent with item.type
    // Look for a `!item.agent` branch that contains `resolveAgent(`
    const guardBlock = engineSrc.match(/if\s*\(\s*!item\.agent[\s\S]{0,400}?resolveAgent\s*\(/);
    assert.ok(guardBlock,
      'Undefined-agent guard must call resolveAgent() to pick a fallback agent');
  });

  // 3. Behavioral: simulate the dispatch loop — undefined agent gets resolved or skipped
  await test('undefined item.agent is replaced via routing before push (behavioral)', () => {
    const pending = [
      { id: 'u-1', agent: undefined, type: 'fix', meta: { item: {} } },
    ];
    const busyAgents = new Set();
    const toDispatch = [];
    // Simulate the guard — pick any configured agent as the fallback
    const cfg = { agents: { dallas: { name: 'Dallas', role: 'Engineer' } } };
    const resolveAgentStub = (type, config) => Object.keys(config.agents)[0] || null;

    for (const item of pending) {
      if (!item.agent) {
        const fallback = resolveAgentStub(item.type || 'fix', cfg);
        if (!fallback) continue;
        item.agent = fallback;
        item.agentName = cfg.agents[fallback]?.name || fallback;
        item.agentRole = cfg.agents[fallback]?.role || 'Agent';
      }
      if (busyAgents.has(item.agent)) continue;
      toDispatch.push(item);
      busyAgents.add(item.agent);
    }

    assert.strictEqual(toDispatch.length, 1, 'Item with resolvable fallback should dispatch');
    assert.strictEqual(toDispatch[0].agent, 'dallas', 'Should be routed to fallback agent');
    assert.strictEqual(toDispatch[0].agentName, 'Dallas', 'agentName should be populated from config');
    assert.strictEqual(toDispatch[0].agentRole, 'Engineer', 'agentRole should be populated from config');
  });

  // 4. Behavioral: if routing returns null (no agents configured), item is skipped
  await test('undefined item.agent with no routable fallback is skipped, never pushed (behavioral)', () => {
    const pending = [
      { id: 'u-2', agent: undefined, type: 'fix', meta: { item: {} } },
    ];
    const toDispatch = [];
    const resolveAgentStub = () => null; // no agents available

    for (const item of pending) {
      if (!item.agent) {
        const fallback = resolveAgentStub();
        if (!fallback) continue;
        item.agent = fallback;
      }
      toDispatch.push(item);
    }

    assert.strictEqual(toDispatch.length, 0,
      'Item must not be pushed to toDispatch when no fallback agent is available');
    // And spawnAgent must never see an item with undefined agent
    assert.strictEqual(toDispatch.find(i => !i.agent), undefined,
      'No item with undefined agent may reach spawn');
  });

  // 5. Source: the guard block persists the resolved agent back to dispatch.json
  //    so the fix survives the tick — mirrors the reassignment-path convention.
  await test('undefined-agent guard persists resolution to dispatch.json (source check)', () => {
    // Look for a mutateDispatch inside the !item.agent guard block
    const block = engineSrc.match(/if\s*\(\s*!item\.agent[\s\S]{0,1500}?mutateDispatch/);
    assert.ok(block,
      'Undefined-agent guard must call mutateDispatch to persist the resolved agent');
  });

  // 6. Source: the guard ships with a log line so this case is diagnosable
  await test('undefined-agent guard emits a log line (source check)', () => {
    const block = engineSrc.match(/if\s*\(\s*!item\.agent[\s\S]{0,1500}?log\s*\(/);
    assert.ok(block,
      'Undefined-agent guard must log when it triggers (for observability)');
  });
}

// ─── #1204: Pending items pre-assigned to unspawned temp agents ─────────────

async function testUnspawnedTempAgentReassignment() {
  console.log('\n── #1204: Unspawned temp agent reassignment ──');

  const engineSrc = fs.readFileSync(path.join(MINIONS_DIR, 'engine.js'), 'utf8');

  // 1. Source: dispatch loop detects pre-assigned unspawned temp agents
  await test('dispatch loop detects pre-assigned temp agents not in active set', () => {
    // Before the busyAgents.has() check, there must be logic that recognizes
    // when item.agent is a temp agent ID that's not currently active/running.
    assert.ok(
      /isUnspawnedTemp|startsWith\(['"]temp-['"]\)/.test(engineSrc),
      'Dispatch loop must detect items pre-assigned to unspawned temp agents'
    );
  });

  // 2. Source: when detected, reroute via resolveAgent so named idle agents can take over
  await test('dispatch loop reroutes unspawned temp agents via resolveAgent', () => {
    // The fix must call resolveAgent near the temp-agent detection in the dispatch loop.
    // Scan all occurrences of startsWith('temp-') in case other paths use the same check.
    const matches = [...engineSrc.matchAll(/startsWith\(['"]temp-['"]\)[\s\S]{0,800}/g)];
    const hasResolveAgentNearby = matches.some(m => /resolveAgent/.test(m[0]));
    assert.ok(
      hasResolveAgentNearby,
      'When a pending item is bound to an unspawned temp agent, the dispatch loop must call resolveAgent to pick a named alternative'
    );
  });

  // 3. Source: reassignment persists to dispatch.json
  await test('unspawned temp reassignment persists via mutateDispatch', () => {
    // The reassignment must persist across ticks via mutateDispatch. Scan all
    // occurrences — at least one must have mutateDispatch within 1500 chars.
    const matches = [...engineSrc.matchAll(/startsWith\(['"]temp-['"]\)[\s\S]{0,1500}/g)];
    const hasMutateDispatchNearby = matches.some(m => /mutateDispatch/.test(m[0]));
    assert.ok(hasMutateDispatchNearby,
      'Unspawned-temp reassignment must persist via mutateDispatch so it survives restarts');
  });

  // 4. Behavioral: item pre-assigned to unspawned temp agent gets reassigned to idle named agent
  await test('unspawned temp agent → idle named agent reassignment (behavioral)', () => {
    const pending = [
      {
        id: 'fix-1',
        agent: 'temp-abc123',        // pre-assigned temp agent that was never spawned
        agentName: 'Temp-abc1',
        agentRole: 'Temporary Agent',
        type: 'fix',
        meta: { item: {}, branch: 'work/P-fix-1' },
      },
    ];
    const active = [];                  // no agents active
    const idleNamedAgents = ['dallas', 'lambert', 'ripley'];

    const busyAgents = new Set(active.map(d => d.agent));
    // Simulate the fix logic
    for (const item of pending) {
      const isUnspawnedTemp = item.agent?.startsWith('temp-') && !busyAgents.has(item.agent);
      if (isUnspawnedTemp) {
        // Simulate resolveAgent picking the first idle named agent
        const altAgent = idleNamedAgents.find(a => !busyAgents.has(a));
        if (altAgent && altAgent !== item.agent) {
          item.agent = altAgent;
          item.agentName = altAgent;
          item.agentRole = 'Agent';
        }
      }
    }

    assert.strictEqual(pending[0].agent, 'dallas',
      'Item should be reassigned from temp-abc123 to the first idle named agent (dallas)');
    assert.notStrictEqual(pending[0].agent, 'temp-abc123',
      'Item should not retain the unspawned temp agent ID when a named agent is idle');
  });

  // 5. Behavioral: item keeps temp agent when ALL named agents are busy
  await test('unspawned temp kept when no named agent idle (behavioral)', () => {
    const pending = [
      { id: 'fix-2', agent: 'temp-xyz456', type: 'fix', meta: { item: {} } },
    ];
    const active = [
      { id: 'dallas-1', agent: 'dallas' },
      { id: 'lambert-1', agent: 'lambert' },
      { id: 'ripley-1', agent: 'ripley' },
    ];
    const namedAgents = ['dallas', 'lambert', 'ripley'];

    const busyAgents = new Set(active.map(d => d.agent));
    for (const item of pending) {
      const isUnspawnedTemp = item.agent?.startsWith('temp-') && !busyAgents.has(item.agent);
      if (isUnspawnedTemp) {
        const altAgent = namedAgents.find(a => !busyAgents.has(a));
        if (altAgent && altAgent !== item.agent) {
          item.agent = altAgent;
        }
      }
    }

    assert.strictEqual(pending[0].agent, 'temp-xyz456',
      'When no named agent is idle, the item should retain its temp agent assignment');
  });

  // 6. Behavioral: an ACTIVE temp agent (in busyAgents) is NOT treated as unspawned
  await test('active temp agent is not treated as unspawned (behavioral)', () => {
    const pending = [
      { id: 'fix-3', agent: 'temp-running', type: 'fix', meta: { item: {} } },
    ];
    const active = [
      { id: 'temp-running-1', agent: 'temp-running' }, // this temp agent IS running
    ];

    const busyAgents = new Set(active.map(d => d.agent));
    let reassigned = false;
    for (const item of pending) {
      const isUnspawnedTemp = item.agent?.startsWith('temp-') && !busyAgents.has(item.agent);
      if (isUnspawnedTemp) reassigned = true;
    }

    assert.strictEqual(reassigned, false,
      'A temp agent currently running (in busyAgents) must not be flagged as unspawned');
  });

  // 7. Behavioral: named agents are untouched
  await test('named agent assignments are not affected (behavioral)', () => {
    const pending = [
      { id: 'fix-4', agent: 'dallas', type: 'fix', meta: { item: {} } },
    ];
    const active = [];

    const busyAgents = new Set(active.map(d => d.agent));
    let reassigned = false;
    for (const item of pending) {
      const isUnspawnedTemp = item.agent?.startsWith('temp-') && !busyAgents.has(item.agent);
      if (isUnspawnedTemp) reassigned = true;
    }

    assert.strictEqual(reassigned, false,
      'Named agent assignments must never be flagged as unspawned temp agents');
    assert.strictEqual(pending[0].agent, 'dallas', 'Named agent should remain unchanged');
  });

  // 8. Source: reassignment runs BEFORE the busyAgents check
  await test('unspawned-temp check appears before busyAgents.has check in dispatch loop', () => {
    // Find positions. The unspawned-temp reassignment logic must execute before
    // `busyAgents.has(item.agent)` so a rerouted item can still be dispatched this tick.
    const dispatchLoopStart = engineSrc.indexOf('for (const item of dispatch.pending)');
    assert.ok(dispatchLoopStart > 0, 'Dispatch loop must exist');

    const tempCheckIdx = engineSrc.indexOf("startsWith('temp-')", dispatchLoopStart);
    const busyCheckIdx = engineSrc.indexOf('busyAgents.has(item.agent)', dispatchLoopStart);

    assert.ok(tempCheckIdx > dispatchLoopStart,
      'The unspawned-temp check must appear inside the dispatch loop');
    assert.ok(busyCheckIdx > dispatchLoopStart,
      'The busyAgents.has check must appear inside the dispatch loop');
    assert.ok(tempCheckIdx < busyCheckIdx,
      'The unspawned-temp reassignment must run before busyAgents.has(item.agent) in the dispatch loop');
  });
}

