// ─── P-c7f1a3b8: Pre-cached gzip status buffer ────────────────────────────

async function testStatusGzipCache() {
  console.log('\n── P-c7f1a3b8: Pre-cached gzip status buffer ──');

  const dashSrc = fs.readFileSync(path.join(MINIONS_DIR, 'dashboard.js'), 'utf8');

  await test('_statusCacheGzip variable exists alongside _statusCacheJson', () => {
    assert.ok(dashSrc.includes('let _statusCacheGzip'),
      'dashboard.js must declare _statusCacheGzip variable');
    // Both should be declared near each other
    const jsonIdx = dashSrc.indexOf('let _statusCacheJson');
    const gzipIdx = dashSrc.indexOf('let _statusCacheGzip');
    assert.ok(Math.abs(gzipIdx - jsonIdx) < 200,
      '_statusCacheGzip must be declared near _statusCacheJson');
  });

  await test('getStatusJson() pre-computes gzip buffer on cache rebuild', () => {
    const fn = dashSrc.match(/function getStatusJson\(\)[\s\S]*?^}/m);
    assert.ok(fn, 'getStatusJson must exist');
    assert.ok(fn[0].includes('_statusCacheGzip') && fn[0].includes('gzipSync'),
      'getStatusJson must compute _statusCacheGzip via gzipSync when rebuilding cache');
  });

  await test('gzipSync called once per cache rebuild, not per request in handleStatus', () => {
    // handleStatus should NOT call gzipSync — it should serve _statusCacheGzip
    const handleStatusStart = dashSrc.indexOf('async function handleStatus(');
    const handleStatusEnd = dashSrc.indexOf('async function', handleStatusStart + 30);
    const handleStatusFn = dashSrc.slice(handleStatusStart, handleStatusEnd > 0 ? handleStatusEnd : handleStatusStart + 1000);
    assert.ok(!handleStatusFn.includes('gzipSync'),
      'handleStatus must NOT call gzipSync — should serve pre-cached _statusCacheGzip');
    assert.ok(handleStatusFn.includes('_statusCacheGzip'),
      'handleStatus must serve the pre-cached _statusCacheGzip buffer');
  });

  await test('handleStatus serves pre-cached gzip when Accept-Encoding includes gzip', () => {
    const handleStatusStart = dashSrc.indexOf('async function handleStatus(');
    const handleStatusEnd = dashSrc.indexOf('async function', handleStatusStart + 30);
    const handleStatusFn = dashSrc.slice(handleStatusStart, handleStatusEnd > 0 ? handleStatusEnd : handleStatusStart + 1000);
    assert.ok(handleStatusFn.includes('accept-encoding') || handleStatusFn.includes('Accept-Encoding'),
      'handleStatus must check Accept-Encoding header');
    assert.ok(handleStatusFn.includes('Content-Encoding') && handleStatusFn.includes('gzip'),
      'handleStatus must set Content-Encoding: gzip when serving cached buffer');
  });

  await test('SSE periodic push uses reference comparison instead of MD5 hash', () => {
    // Find the setInterval for periodic push (the 10000ms one)
    const intervalMatch = dashSrc.match(/setInterval\(\(\) => \{[\s\S]*?_statusStreamClients[\s\S]*?\}, 10000\)/);
    assert.ok(intervalMatch, 'SSE periodic push interval must exist');
    const intervalBody = intervalMatch[0];
    // Must NOT use MD5 hash
    assert.ok(!intervalBody.includes('createHash') && !intervalBody.includes('md5'),
      'SSE periodic push must NOT use MD5 hash — use reference comparison');
    // Should use reference comparison (checking if data !== _lastXxx or similar)
    assert.ok(!intervalBody.includes('.digest('),
      'SSE periodic push must not compute hash digests');
  });

  await test('_lastStatusHash is removed or replaced with reference-based tracking', () => {
    // The old _lastStatusHash should be replaced
    const intervalMatch = dashSrc.match(/setInterval\(\(\) => \{[\s\S]*?_statusStreamClients[\s\S]*?\}, 10000\)/);
    assert.ok(intervalMatch, 'SSE periodic push interval must exist');
    const intervalBody = intervalMatch[0];
    // Should have some form of "last" reference comparison
    assert.ok(intervalBody.includes('===') || intervalBody.includes('!=='),
      'SSE periodic push must use reference equality for change detection');
  });

  await test('invalidateStatusCache clears _statusCacheGzip', () => {
    const fn = dashSrc.match(/function invalidateStatusCache\s*\([^)]*\)[\s\S]*?^}/m);
    assert.ok(fn, 'invalidateStatusCache must exist');
    assert.ok(fn[0].includes('_statusCacheGzip = null') || fn[0].includes('_statusCacheGzip=null'),
      'invalidateStatusCache must clear _statusCacheGzip');
  });

  await test('getStatus cache rebuild invalidates _statusCacheGzip', () => {
    // When _statusCache is rebuilt in getStatus(), both _statusCacheJson and _statusCacheGzip are invalidated
    const fn = dashSrc.match(/function getStatus\(\)[\s\S]*?^}/m);
    assert.ok(fn, 'getStatus must exist');
    assert.ok(fn[0].includes('_statusCacheGzip = null') || fn[0].includes('_statusCacheGzip=null'),
      'getStatus must invalidate _statusCacheGzip when rebuilding cache');
  });

  await test('jsonReply still gzips normally for non-status endpoints', () => {
    const fn = dashSrc.match(/function jsonReply[\s\S]*?^}/m);
    assert.ok(fn, 'jsonReply must exist');
    assert.ok(fn[0].includes('gzipSync'),
      'jsonReply must still call gzipSync for non-status endpoints');
  });
}

// ─── P-a5e9c1d7: Split getStatus() into fast/slow state tiers ───────────────

async function testStatusCacheTiers() {
  console.log('\n── Status Cache Tiers (fast/slow) ──');

  const dashSrc = fs.readFileSync(path.join(MINIONS_DIR, 'dashboard.js'), 'utf8');

  // ── Tier variables and TTLs exist ──

  await test('dashboard.js has _fastState and _slowState cache variables', () => {
    assert.ok(dashSrc.includes('let _fastState'), '_fastState variable must exist');
    assert.ok(dashSrc.includes('let _slowState'), '_slowState variable must exist');
    assert.ok(dashSrc.includes('let _fastStateTs'), '_fastStateTs timestamp must exist');
    assert.ok(dashSrc.includes('let _slowStateTs'), '_slowStateTs timestamp must exist');
  });

  await test('FAST_STATE_TTL is 10s and SLOW_STATE_TTL is 60s', () => {
    assert.ok(dashSrc.includes('FAST_STATE_TTL = 10000'), 'FAST_STATE_TTL must be 10000ms (10s)');
    assert.ok(dashSrc.includes('SLOW_STATE_TTL = 60000'), 'SLOW_STATE_TTL must be 60000ms (60s)');
  });

  // ── Fast state contains the right keys ──

  await test('fast state includes frequently-changing data', () => {
    const statusFn = dashSrc.match(/function getStatus\(\)[\s\S]*?^}/m);
    assert.ok(statusFn, 'getStatus must exist');
    const body = statusFn[0];
    // These must appear in the _fastState assignment
    assert.ok(body.includes('_fastState'), 'getStatus must build _fastState');
    for (const key of ['agents:', 'inbox:', 'pullRequests:', 'dispatch:', 'metrics:', 'workItems:', 'watches:', 'meetings:', 'adoThrottle:', 'ghThrottle:', 'engineLog:']) {
      assert.ok(body.includes(key), `fast state must include ${key}`);
    }
  });

  // ── Slow state contains the right keys ──

  await test('slow state includes rarely-changing data', () => {
    const statusFn = dashSrc.match(/function getStatus\(\)[\s\S]*?^}/m);
    assert.ok(statusFn, 'getStatus must exist');
    const body = statusFn[0];
    assert.ok(body.includes('_slowState'), 'getStatus must build _slowState');
    for (const key of ['skills:', 'prdProgress:', 'mcpServers:', 'pinned:', 'projects:', 'autoMode:', 'version:', 'schedules:']) {
      assert.ok(body.includes(key), `slow state must include ${key}`);
    }
  });

  // ── invalidateStatusCache invalidates fast state only ──

  await test('invalidateStatusCache nullifies _fastState unconditionally and _slowState only on opt-in', () => {
    const fn = dashSrc.match(/function invalidateStatusCache\s*\([^)]*\)[\s\S]*?^}/m);
    assert.ok(fn, 'invalidateStatusCache must exist');
    const body = fn[0];
    assert.ok(body.includes('_fastState = null'), 'must nullify _fastState unconditionally');
    // _slowState = null (if present) must be gated behind includeSlow — default TTL behaviour preserved
    const slowIdx = body.indexOf('_slowState = null');
    if (slowIdx > 0) {
      const before = body.slice(0, slowIdx);
      assert.ok(/includeSlow/.test(before),
        '_slowState = null must be inside an includeSlow branch — default must leave slow state on its TTL');
    }
  });

  // ── mtime tracking applies to fast state only ──

  await test('mtime-based validation applies only to fast-state TTL check', () => {
    const statusFn = dashSrc.match(/function getStatus\(\)[\s\S]*?^}/m);
    assert.ok(statusFn, 'getStatus must exist');
    const body = statusFn[0];
    // The mtime check should be near _fastState logic, not _slowState
    const fastIdx = body.indexOf('_fastState');
    const mtimeIdx = body.indexOf('_mtimesChanged');
    const slowIdx = body.indexOf('_slowState');
    assert.ok(fastIdx > 0 && mtimeIdx > 0 && slowIdx > 0, 'all three markers must exist');
    // mtime check should appear before or near fast state, not after slow state assignment
    assert.ok(mtimeIdx < slowIdx, 'mtime validation must appear before slow state building (applies to fast tier only)');
  });

  // ── getStatus merges both tiers ──

  await test('getStatus merges fast and slow state into combined _statusCache', () => {
    const statusFn = dashSrc.match(/function getStatus\(\)[\s\S]*?^}/m);
    assert.ok(statusFn, 'getStatus must exist');
    const body = statusFn[0];
    // The final _statusCache should spread both tiers
    assert.ok(body.includes('..._fastState') && body.includes('..._slowState'),
      'getStatus must merge _fastState and _slowState via spread into _statusCache');
    assert.ok(body.includes('timestamp:'), 'merged status must include timestamp');
  });

  // ── Slow state is NOT rebuilt when only fast state changes ──

  await test('slow state rebuild is gated by SLOW_STATE_TTL only (no mtime check)', () => {
    const statusFn = dashSrc.match(/function getStatus\(\)[\s\S]*?^}/m);
    assert.ok(statusFn, 'getStatus must exist');
    const body = statusFn[0];
    // The slowStale check should reference SLOW_STATE_TTL, not _mtimesChanged
    assert.ok(body.includes('SLOW_STATE_TTL'), 'slow state staleness must be gated by SLOW_STATE_TTL');
    // Extract the slowStale logic — it should be a simple TTL check
    const slowStaleMatch = body.match(/slowStale\s*=.*SLOW_STATE_TTL/);
    assert.ok(slowStaleMatch, 'slowStale must be determined by SLOW_STATE_TTL comparison');
  });
}

// ─── W-moczd52c1icm: dashboard.js pure helpers ──────────────────────────────
//
// Exercises five pure helpers exported from dashboard.js:
//   getMcpServers, _filterCcTabSessions, _getVersionCheckInterval,
//   _parseWatchInterval, parsePinnedEntries.
// Dashboard.js is required once lazily so module-load side effects (HTML
// assembly, fs.watch, npm version check) only fire when these tests run.

async function testDashboardPureHelpers() {
  console.log('\n── dashboard.js — pure helpers ──');

  // Lazy require — dashboard.js guards server.listen/watchdog/signal handlers
  // behind `require.main === module`, so loading it here is safe.
  const dashboard = require(path.join(MINIONS_DIR, 'dashboard'));
  const { getMcpServers, _filterCcTabSessions, _getVersionCheckInterval,
          _parseWatchInterval, parsePinnedEntries } = dashboard;
  const queriesMod = require(path.join(MINIONS_DIR, 'engine', 'queries'));
  const osMod = require('os');

  // ── _parseWatchInterval ──────────────────────────────────────────────────
  // Pure function — no patching, just input → output.

  await test('_parseWatchInterval returns default 300000 for null', () => {
    assert.strictEqual(_parseWatchInterval(null), 300000);
  });

  await test('_parseWatchInterval returns default 300000 for undefined', () => {
    assert.strictEqual(_parseWatchInterval(undefined), 300000);
  });

  await test('_parseWatchInterval returns default for empty string', () => {
    assert.strictEqual(_parseWatchInterval(''), 300000);
  });

  await test('_parseWatchInterval returns default for falsy 0', () => {
    // 0 is falsy, hits the `if (!val)` branch — documents actual behavior.
    assert.strictEqual(_parseWatchInterval(0), 300000);
  });

  await test('_parseWatchInterval passes through ms number >= 60000', () => {
    assert.strictEqual(_parseWatchInterval(300000), 300000);
    assert.strictEqual(_parseWatchInterval(3600000), 3600000);
  });

  await test('_parseWatchInterval clamps numeric input below 60000 floor', () => {
    assert.strictEqual(_parseWatchInterval(1000), 60000);
    assert.strictEqual(_parseWatchInterval(59999), 60000);
  });

  await test('_parseWatchInterval parses "5m" as 5 minutes', () => {
    assert.strictEqual(_parseWatchInterval('5m'), 300000);
  });

  await test('_parseWatchInterval parses "1h" as 1 hour', () => {
    assert.strictEqual(_parseWatchInterval('1h'), 3600000);
  });

  await test('_parseWatchInterval parses "30s" and clamps to 60000 floor', () => {
    assert.strictEqual(_parseWatchInterval('30s'), 60000);
  });

  await test('_parseWatchInterval parses "120s" as 120 seconds', () => {
    assert.strictEqual(_parseWatchInterval('120s'), 120000);
  });

  await test('_parseWatchInterval parses fractional "1.5m"', () => {
    assert.strictEqual(_parseWatchInterval('1.5m'), 90000);
  });

  await test('_parseWatchInterval accepts "min" / "hr" / "hours" / "sec" suffixes', () => {
    assert.strictEqual(_parseWatchInterval('5min'), 300000);
    assert.strictEqual(_parseWatchInterval('2hr'), 7200000);
    assert.strictEqual(_parseWatchInterval('2hours'), 7200000);
    assert.strictEqual(_parseWatchInterval('120sec'), 120000);
  });

  await test('_parseWatchInterval parses numeric string >= 1000 as milliseconds', () => {
    assert.strictEqual(_parseWatchInterval('300000'), 300000);
    assert.strictEqual(_parseWatchInterval('120000'), 120000);
  });

  await test('_parseWatchInterval parses numeric string < 1000 as seconds with clamp', () => {
    // "500" → 500 * 1000 ms = 500000ms, above floor → 500000
    assert.strictEqual(_parseWatchInterval('500'), 500000);
    // "30" → 30 * 1000 = 30000ms, below floor → clamped to 60000
    assert.strictEqual(_parseWatchInterval('30'), 60000);
  });

  await test('_parseWatchInterval returns default for unrecognized input', () => {
    assert.strictEqual(_parseWatchInterval('xyz'), 300000);
    assert.strictEqual(_parseWatchInterval('5days'), 300000);
    assert.strictEqual(_parseWatchInterval('5 years'), 300000);
  });

  await test('_parseWatchInterval tolerates whitespace around unit', () => {
    assert.strictEqual(_parseWatchInterval('5 m'), 300000);
    assert.strictEqual(_parseWatchInterval('  10m  '), 600000);
  });

  // ── parsePinnedEntries ──────────────────────────────────────────────────

  await test('parsePinnedEntries returns [] for empty string', () => {
    assert.deepStrictEqual(parsePinnedEntries(''), []);
  });

  await test('parsePinnedEntries returns [] for null / undefined', () => {
    assert.deepStrictEqual(parsePinnedEntries(null), []);
    assert.deepStrictEqual(parsePinnedEntries(undefined), []);
  });

  await test('parsePinnedEntries parses single entry without emoji as info', () => {
    const content = '### Plain Title\n\nBody line one';
    const result = parsePinnedEntries(content);
    assert.strictEqual(result.length, 1);
    assert.strictEqual(result[0].level, 'info');
    assert.strictEqual(result[0].title, 'Plain Title');
    assert.strictEqual(result[0].content, 'Body line one');
  });

  await test('parsePinnedEntries marks 🔴 entries as critical', () => {
    const content = '### 🔴 Critical Rule\n\nDo this always';
    const result = parsePinnedEntries(content);
    assert.strictEqual(result.length, 1);
    assert.strictEqual(result[0].level, 'critical');
    assert.strictEqual(result[0].title, 'Critical Rule');
  });

  await test('parsePinnedEntries marks 🟡 entries as warning', () => {
    const content = '### 🟡 Heads Up\n\nPotential gotcha';
    const result = parsePinnedEntries(content);
    assert.strictEqual(result.length, 1);
    assert.strictEqual(result[0].level, 'warning');
    assert.strictEqual(result[0].title, 'Heads Up');
  });

  await test('parsePinnedEntries terminates content at *Pinned signature', () => {
    const content = '### Tip\n\nActual tip body\n\n*Pinned by alice on 2026-01-01*';
    const result = parsePinnedEntries(content);
    assert.strictEqual(result.length, 1);
    assert.strictEqual(result[0].content, 'Actual tip body');
    // signature line must NOT leak into content
    assert.ok(!result[0].content.includes('*Pinned'),
      'signature line must not appear in parsed content');
  });

  await test('parsePinnedEntries handles multiple entries separated by ###', () => {
    const content = '### 🔴 Rule One\n\nFirst body\n\n### 🟡 Rule Two\n\nSecond body';
    const result = parsePinnedEntries(content);
    assert.strictEqual(result.length, 2);
    assert.strictEqual(result[0].level, 'critical');
    assert.strictEqual(result[0].title, 'Rule One');
    assert.strictEqual(result[0].content, 'First body');
    assert.strictEqual(result[1].level, 'warning');
    assert.strictEqual(result[1].title, 'Rule Two');
    assert.strictEqual(result[1].content, 'Second body');
  });

  await test('parsePinnedEntries skips malformed entry missing blank line after title', () => {
    // No blank line between title and body → regex does not match
    const content = '### Not Structured\nBody on next line only';
    assert.deepStrictEqual(parsePinnedEntries(content), []);
  });

  await test('parsePinnedEntries preserves multi-line content inside one entry', () => {
    const content = '### Title\n\nLine one\nLine two\nLine three';
    const result = parsePinnedEntries(content);
    assert.strictEqual(result.length, 1);
    assert.strictEqual(result[0].content, 'Line one\nLine two\nLine three');
  });

  // ── _filterCcTabSessions ────────────────────────────────────────────────

  const freshSession = () => ({
    id: 'tab-1',
    sessionId: 'sess-abc',
    turnCount: 0,
    lastActiveAt: new Date().toISOString(),
  });

  await test('_filterCcTabSessions returns [] for non-array input', () => {
    assert.deepStrictEqual(_filterCcTabSessions(null), []);
    assert.deepStrictEqual(_filterCcTabSessions(undefined), []);
    assert.deepStrictEqual(_filterCcTabSessions('not an array'), []);
    assert.deepStrictEqual(_filterCcTabSessions({}), []);
  });

  await test('_filterCcTabSessions keeps a fresh session with no _promptHash', () => {
    const kept = _filterCcTabSessions([freshSession()]);
    assert.strictEqual(kept.length, 1);
    assert.strictEqual(kept[0].id, 'tab-1');
  });

  await test('_filterCcTabSessions drops sessions missing id or sessionId', () => {
    const s1 = { ...freshSession(), id: null };
    const s2 = { ...freshSession(), sessionId: null };
    const s3 = null; // falsy session entries also rejected
    assert.deepStrictEqual(_filterCcTabSessions([s1, s2, s3]), []);
  });

  await test('_filterCcTabSessions drops sessions with turnCount >= CC_SESSION_MAX_TURNS', () => {
    const max = shared.ENGINE_DEFAULTS.ccMaxTurns;
    const overTurns = { ...freshSession(), turnCount: max };
    const wayOver = { ...freshSession(), turnCount: max + 10 };
    assert.deepStrictEqual(_filterCcTabSessions([overTurns, wayOver]), []);
  });

  await test('_filterCcTabSessions keeps sessions with turnCount < CC_SESSION_MAX_TURNS', () => {
    const max = shared.ENGINE_DEFAULTS.ccMaxTurns;
    const underTurns = { ...freshSession(), turnCount: max - 1 };
    const kept = _filterCcTabSessions([underTurns]);
    assert.strictEqual(kept.length, 1);
    assert.strictEqual(kept[0].turnCount, max - 1);
  });

  await test('_filterCcTabSessions drops sessions whose lastActiveAt is past TTL', () => {
    const ttl = shared.ENGINE_DEFAULTS.ccSessionTtlMs;
    const expired = {
      ...freshSession(),
      lastActiveAt: new Date(Date.now() - ttl - 60000).toISOString(),
    };
    assert.deepStrictEqual(_filterCcTabSessions([expired]), []);
  });

  await test('_filterCcTabSessions falls back to createdAt when lastActiveAt missing', () => {
    const ttl = shared.ENGINE_DEFAULTS.ccSessionTtlMs;
    const expiredByCreatedAt = {
      id: 'tab-2',
      sessionId: 'sess-2',
      turnCount: 0,
      createdAt: new Date(Date.now() - ttl - 60000).toISOString(),
    };
    assert.deepStrictEqual(_filterCcTabSessions([expiredByCreatedAt]), []);

    const freshByCreatedAt = {
      id: 'tab-3',
      sessionId: 'sess-3',
      turnCount: 0,
      createdAt: new Date().toISOString(),
    };
    assert.strictEqual(_filterCcTabSessions([freshByCreatedAt]).length, 1);
  });

  await test('_filterCcTabSessions drops sessions whose _promptHash does not match current hash', () => {
    // A _promptHash that is definitely not the current 8-char md5 slice.
    const mismatched = { ...freshSession(), _promptHash: 'deadbeef-impossible-hash' };
    assert.deepStrictEqual(_filterCcTabSessions([mismatched]), []);
  });

  await test('_filterCcTabSessions filters a mixed list, keeping only valid sessions', () => {
    const ttl = shared.ENGINE_DEFAULTS.ccSessionTtlMs;
    const max = shared.ENGINE_DEFAULTS.ccMaxTurns;
    const sessions = [
      freshSession(),                                                            // keep
      { ...freshSession(), id: null },                                           // drop (no id)
      { ...freshSession(), turnCount: max },                                     // drop (turns)
      { ...freshSession(), lastActiveAt: new Date(Date.now() - ttl - 1).toISOString() }, // drop (expired)
      { ...freshSession(), _promptHash: 'wrong-hash-12345' },                    // drop (hash mismatch)
      freshSession(),                                                            // keep
    ];
    const kept = _filterCcTabSessions(sessions);
    assert.strictEqual(kept.length, 2);
    for (const s of kept) {
      assert.ok(s.id && s.sessionId, 'kept sessions must have id and sessionId');
      assert.ok(s.turnCount < max, 'kept sessions must be under the turn cap');
    }
  });

  // ── _getVersionCheckInterval (patches queries.getConfig) ───────────────

  await test('_getVersionCheckInterval returns default when config omits override', () => {
    const orig = queriesMod.getConfig;
    queriesMod.getConfig = () => ({ engine: {} });
    try {
      assert.strictEqual(_getVersionCheckInterval(),
        shared.ENGINE_DEFAULTS.versionCheckInterval);
    } finally {
      queriesMod.getConfig = orig;
    }
  });

  await test('_getVersionCheckInterval returns default when config has no engine section', () => {
    const orig = queriesMod.getConfig;
    queriesMod.getConfig = () => ({});
    try {
      assert.strictEqual(_getVersionCheckInterval(),
        shared.ENGINE_DEFAULTS.versionCheckInterval);
    } finally {
      queriesMod.getConfig = orig;
    }
  });

  await test('_getVersionCheckInterval returns config override when present', () => {
    const orig = queriesMod.getConfig;
    queriesMod.getConfig = () => ({ engine: { versionCheckInterval: 1234567 } });
    try {
      assert.strictEqual(_getVersionCheckInterval(), 1234567);
    } finally {
      queriesMod.getConfig = orig;
    }
  });

  await test('_getVersionCheckInterval falls back to default when getConfig throws', () => {
    const orig = queriesMod.getConfig;
    queriesMod.getConfig = () => { throw new Error('boom'); };
    try {
      assert.strictEqual(_getVersionCheckInterval(),
        shared.ENGINE_DEFAULTS.versionCheckInterval);
    } finally {
      queriesMod.getConfig = orig;
    }
  });

  await test('_getVersionCheckInterval treats versionCheckInterval=0 as missing (falsy)', () => {
    // `?.versionCheckInterval || default` — 0 is falsy, so the default wins.
    // Documents actual behavior; 0 would otherwise mean "check immediately always".
    const orig = queriesMod.getConfig;
    queriesMod.getConfig = () => ({ engine: { versionCheckInterval: 0 } });
    try {
      assert.strictEqual(_getVersionCheckInterval(),
        shared.ENGINE_DEFAULTS.versionCheckInterval);
    } finally {
      queriesMod.getConfig = orig;
    }
  });

  // ── getMcpServers (patches os.homedir) ────────────────────────────────

  await test('getMcpServers returns [] when ~/.claude.json is missing', () => {
    const origHome = osMod.homedir;
    const tmp = createTmpDir(); // empty dir, no .claude.json
    osMod.homedir = () => tmp;
    try {
      assert.deepStrictEqual(getMcpServers(), []);
    } finally {
      osMod.homedir = origHome;
    }
  });

  await test('getMcpServers returns [] when ~/.claude.json is malformed', () => {
    const origHome = osMod.homedir;
    const tmp = createTmpDir();
    fs.writeFileSync(path.join(tmp, '.claude.json'), '{ this is not json');
    osMod.homedir = () => tmp;
    try {
      assert.deepStrictEqual(getMcpServers(), []);
    } finally {
      osMod.homedir = origHome;
    }
  });

  await test('getMcpServers returns [] when config lacks mcpServers key', () => {
    const origHome = osMod.homedir;
    const tmp = createTmpDir();
    fs.writeFileSync(path.join(tmp, '.claude.json'), JSON.stringify({ other: 1 }));
    osMod.homedir = () => tmp;
    try {
      assert.deepStrictEqual(getMcpServers(), []);
    } finally {
      osMod.homedir = origHome;
    }
  });

  await test('getMcpServers maps mcpServers entries to {name, command, args}', () => {
    const origHome = osMod.homedir;
    const tmp = createTmpDir();
    fs.writeFileSync(path.join(tmp, '.claude.json'), JSON.stringify({
      mcpServers: {
        playwright: { command: 'npx', args: ['-y', '@playwright/mcp@latest'] },
        azure: { command: 'azmcp', args: ['server', 'start'] },
      },
    }));
    osMod.homedir = () => tmp;
    try {
      const servers = getMcpServers();
      assert.strictEqual(servers.length, 2);
      const byName = Object.fromEntries(servers.map(s => [s.name, s]));
      assert.strictEqual(byName.playwright.command, 'npx');
      // slice(-1)[0] returns the LAST arg (documents current behavior)
      assert.strictEqual(byName.playwright.args, '@playwright/mcp@latest');
      assert.strictEqual(byName.azure.command, 'azmcp');
      assert.strictEqual(byName.azure.args, 'start');
    } finally {
      osMod.homedir = origHome;
    }
  });

  await test('getMcpServers defaults missing command/args fields to empty string', () => {
    const origHome = osMod.homedir;
    const tmp = createTmpDir();
    fs.writeFileSync(path.join(tmp, '.claude.json'), JSON.stringify({
      mcpServers: {
        minimal: {},                      // no command, no args
        commandOnly: { command: 'node' }, // no args
        emptyArgs: { command: 'foo', args: [] }, // args present but empty
      },
    }));
    osMod.homedir = () => tmp;
    try {
      const servers = getMcpServers();
      const byName = Object.fromEntries(servers.map(s => [s.name, s]));
      assert.strictEqual(byName.minimal.command, '');
      assert.strictEqual(byName.minimal.args, '');
      assert.strictEqual(byName.commandOnly.command, 'node');
      assert.strictEqual(byName.commandOnly.args, '');
      assert.strictEqual(byName.emptyArgs.command, 'foo');
      assert.strictEqual(byName.emptyArgs.args, '');
    } finally {
      osMod.homedir = origHome;
    }
  });

  await test('getMcpServers returns [] when mcpServers is an empty object', () => {
    const origHome = osMod.homedir;
    const tmp = createTmpDir();
    fs.writeFileSync(path.join(tmp, '.claude.json'), JSON.stringify({ mcpServers: {} }));
    osMod.homedir = () => tmp;
    try {
      assert.deepStrictEqual(getMcpServers(), []);
    } finally {
      osMod.homedir = origHome;
    }
  });
}

// ─── W-moczcvjl338u: engine.js pure helpers ──────────────────────────────────

async function testEngineHelperCoverage() {
  console.log('\n── engine.js — pure helper coverage (W-moczcvjl338u) ──');

  const engine = require(path.join(MINIONS_DIR, 'engine.js'));
  const { ENGINE_DEFAULTS, WORK_TYPE } = shared;

  // ── normalizeAc ──

  await test('normalizeAc returns array input unchanged (identity)', () => {
    const input = ['write test', 'ship it'];
    const out = engine.normalizeAc(input);
    assert.strictEqual(out, input, 'array input must be returned as-is (same reference)');
  });

  await test('normalizeAc returns empty array for null', () => {
    assert.deepStrictEqual(engine.normalizeAc(null), []);
  });

  await test('normalizeAc returns empty array for undefined', () => {
    assert.deepStrictEqual(engine.normalizeAc(undefined), []);
  });

  await test('normalizeAc returns empty array for numeric input', () => {
    assert.deepStrictEqual(engine.normalizeAc(42), []);
  });

  await test('normalizeAc returns empty array for plain object', () => {
    assert.deepStrictEqual(engine.normalizeAc({ foo: 'bar' }), []);
  });

  await test('normalizeAc returns empty array for empty string', () => {
    assert.deepStrictEqual(engine.normalizeAc(''), []);
  });

  await test('normalizeAc returns empty array for whitespace-only string', () => {
    // Each line trims to '' → filtered out
    assert.deepStrictEqual(engine.normalizeAc('   \n  \n'), []);
  });

  await test('normalizeAc splits newline-delimited string and preserves order', () => {
    const out = engine.normalizeAc('first\nsecond\nthird');
    assert.deepStrictEqual(out, ['first', 'second', 'third']);
  });

  await test('normalizeAc strips leading dash markers from string lines', () => {
    const out = engine.normalizeAc('- alpha\n- beta');
    assert.deepStrictEqual(out, ['alpha', 'beta']);
  });

  await test('normalizeAc strips leading asterisk markers from string lines', () => {
    const out = engine.normalizeAc('* alpha\n* beta');
    assert.deepStrictEqual(out, ['alpha', 'beta']);
  });

  await test('normalizeAc only strips a single leading marker, not interior ones', () => {
    const out = engine.normalizeAc('- use a - dash inside');
    assert.deepStrictEqual(out, ['use a - dash inside']);
  });

  await test('normalizeAc skips empty lines and trims trailing whitespace', () => {
    // Regex `/^[-*]\s*/` requires marker at column 0 — leading whitespace is
    // preserved verbatim and the line survives the trim() as-is (sans outer ws)
    const out = engine.normalizeAc('- alpha  \n\n- beta\n   \n- gamma');
    assert.deepStrictEqual(out, ['alpha', 'beta', 'gamma']);
  });

  await test('normalizeAc does NOT strip markers when preceded by whitespace (regex anchored at ^)', () => {
    // Documents current behaviour: leading whitespace shields the marker from
    // being stripped. trim() still fires, so the returned line keeps the marker.
    const out = engine.normalizeAc('  - alpha\n  * beta');
    assert.deepStrictEqual(out, ['- alpha', '* beta']);
  });

  await test('normalizeAc handles CRLF line endings gracefully', () => {
    // Only '\n' is a separator — '\r' remains attached then is trimmed away
    const out = engine.normalizeAc('- alpha\r\n- beta\r\n');
    assert.deepStrictEqual(out, ['alpha', 'beta']);
  });

  await test('normalizeAc preserves empty array input', () => {
    const out = engine.normalizeAc([]);
    assert.deepStrictEqual(out, []);
  });

  // ── _maxTurnsForType ──

  await test('_maxTurnsForType returns built-in default per WORK_TYPE when no config overrides', () => {
    const expected = {
      [WORK_TYPE.EXPLORE]: 30, [WORK_TYPE.ASK]: 20, [WORK_TYPE.REVIEW]: 30,
      [WORK_TYPE.DECOMPOSE]: 15, [WORK_TYPE.PLAN]: 30, [WORK_TYPE.PLAN_TO_PRD]: 35,
      [WORK_TYPE.MEETING]: 30, [WORK_TYPE.IMPLEMENT]: 75, [WORK_TYPE.IMPLEMENT_LARGE]: 75,
      [WORK_TYPE.FIX]: 75, [WORK_TYPE.TEST]: 50, [WORK_TYPE.VERIFY]: 100, [WORK_TYPE.DOCS]: 30,
    };
    for (const [type, turns] of Object.entries(expected)) {
      assert.strictEqual(engine._maxTurnsForType(type, {}), turns,
        `${type} should resolve to built-in default ${turns}`);
    }
  });

  await test('_maxTurnsForType falls back to ENGINE_DEFAULTS.maxTurns for unknown types', () => {
    assert.strictEqual(engine._maxTurnsForType('unknown-work-type', {}), ENGINE_DEFAULTS.maxTurns);
  });

  await test('_maxTurnsForType ignores global maxTurns when it equals the default', () => {
    // Same as default → treated as "no override"; built-in per-type wins
    const out = engine._maxTurnsForType(WORK_TYPE.IMPLEMENT, { maxTurns: ENGINE_DEFAULTS.maxTurns });
    assert.strictEqual(out, 75);
  });

  await test('_maxTurnsForType applies global maxTurns override (overrides built-in per-type)', () => {
    const out = engine._maxTurnsForType(WORK_TYPE.IMPLEMENT, { maxTurns: ENGINE_DEFAULTS.maxTurns + 50 });
    assert.strictEqual(out, ENGINE_DEFAULTS.maxTurns + 50);
  });

  await test('_maxTurnsForType applies global maxTurns override for unknown type', () => {
    const out = engine._maxTurnsForType('unknown-xyz', { maxTurns: ENGINE_DEFAULTS.maxTurns + 7 });
    assert.strictEqual(out, ENGINE_DEFAULTS.maxTurns + 7);
  });

  await test('_maxTurnsForType per-type override beats global override', () => {
    const out = engine._maxTurnsForType(WORK_TYPE.IMPLEMENT, {
      maxTurns: ENGINE_DEFAULTS.maxTurns + 50,
      maxTurnsByType: { [WORK_TYPE.IMPLEMENT]: 200 },
    });
    assert.strictEqual(out, 200);
  });

  await test('_maxTurnsForType per-type override beats built-in per-type default', () => {
    const out = engine._maxTurnsForType(WORK_TYPE.REVIEW, {
      maxTurnsByType: { [WORK_TYPE.REVIEW]: 9 },
    });
    assert.strictEqual(out, 9);
  });

  await test('_maxTurnsForType per-type override for unlisted type wins over default', () => {
    const out = engine._maxTurnsForType('custom-type', {
      maxTurnsByType: { 'custom-type': 42 },
    });
    assert.strictEqual(out, 42);
  });

  await test('_maxTurnsForType ignores per-type override of 0 (falsy) and falls through', () => {
    // perType[type] is checked with truthy test, so 0 falls through to next branch
    const out = engine._maxTurnsForType(WORK_TYPE.IMPLEMENT, {
      maxTurnsByType: { [WORK_TYPE.IMPLEMENT]: 0 },
    });
    assert.strictEqual(out, 75, 'zero per-type override must not apply; falls through to built-in 75');
  });

  // ── isWorktreeRetryableError ──

  await test('isWorktreeRetryableError returns false for null/undefined err', () => {
    assert.strictEqual(engine.isWorktreeRetryableError(null), false);
    assert.strictEqual(engine.isWorktreeRetryableError(undefined), false);
  });

  await test('isWorktreeRetryableError returns false for err without message field', () => {
    assert.strictEqual(engine.isWorktreeRetryableError({}), false);
    assert.strictEqual(engine.isWorktreeRetryableError({ code: 'ENOENT' }), false);
  });

  await test('isWorktreeRetryableError returns false for unrelated error message', () => {
    assert.strictEqual(engine.isWorktreeRetryableError(new Error('nothing to do here')), false);
    assert.strictEqual(engine.isWorktreeRetryableError(new Error('permission denied')), false);
  });

  await test('isWorktreeRetryableError matches ETIMEDOUT', () => {
    assert.strictEqual(engine.isWorktreeRetryableError(new Error('operation ETIMEDOUT after 30s')), true);
  });

  await test('isWorktreeRetryableError matches index.lock substring', () => {
    assert.strictEqual(engine.isWorktreeRetryableError(new Error('unable to create .git/index.lock: File exists')), true);
  });

  await test('isWorktreeRetryableError matches "timed out"', () => {
    assert.strictEqual(engine.isWorktreeRetryableError(new Error('git worktree add timed out')), true);
  });

  await test('isWorktreeRetryableError matches "could not lock"', () => {
    assert.strictEqual(engine.isWorktreeRetryableError(new Error('fatal: could not lock config file')), true);
  });

  await test('isWorktreeRetryableError matches "resource busy"', () => {
    assert.strictEqual(engine.isWorktreeRetryableError(new Error('EBUSY: resource busy or locked')), true);
  });

  await test('isWorktreeRetryableError matches "already exists"', () => {
    assert.strictEqual(engine.isWorktreeRetryableError(new Error("fatal: '<path>' already exists")), true);
  });

  await test('isWorktreeRetryableError is case-sensitive on substring match', () => {
    // Current implementation uses plain .includes(), so case matters
    assert.strictEqual(engine.isWorktreeRetryableError(new Error('Etimedout')), false,
      'implementation uses case-sensitive includes — lowercase/mixed-case should not match');
  });

  await test('isWorktreeRetryableError coerces non-Error values via String(err?.message)', () => {
    // err.message is undefined on a plain string, so msg === 'undefined' and no pattern matches
    assert.strictEqual(engine.isWorktreeRetryableError('ETIMEDOUT raw string'), false);
    // But object with matching .message works
    assert.strictEqual(engine.isWorktreeRetryableError({ message: 'ETIMEDOUT' }), true);
  });

  // ── removeStaleIndexLock ──

  await test('removeStaleIndexLock is a no-op when .git/index.lock does not exist', () => {
    const dir = createTmpDir();
    fs.mkdirSync(path.join(dir, '.git'), { recursive: true });
    // Must not throw
    engine.removeStaleIndexLock(dir);
    // And must not spontaneously create the lock
    assert.ok(!fs.existsSync(path.join(dir, '.git', 'index.lock')));
  });

  await test('removeStaleIndexLock is a no-op when .git directory does not exist', () => {
    const dir = createTmpDir();
    // No .git at all
    engine.removeStaleIndexLock(dir); // must not throw
  });

  await test('removeStaleIndexLock removes lock older than 300_000ms', () => {
    const dir = createTmpDir();
    fs.mkdirSync(path.join(dir, '.git'), { recursive: true });
    const lockFile = path.join(dir, '.git', 'index.lock');
    fs.writeFileSync(lockFile, '');
    // Backdate mtime to 10 minutes ago
    const oldTime = new Date(Date.now() - 600000);
    fs.utimesSync(lockFile, oldTime, oldTime);
    engine.removeStaleIndexLock(dir);
    assert.ok(!fs.existsSync(lockFile), 'stale index.lock must be removed');
  });

  await test('removeStaleIndexLock preserves fresh lock (younger than 300_000ms)', () => {
    const dir = createTmpDir();
    fs.mkdirSync(path.join(dir, '.git'), { recursive: true });
    const lockFile = path.join(dir, '.git', 'index.lock');
    fs.writeFileSync(lockFile, '');
    // Fresh lock — just now
    engine.removeStaleIndexLock(dir);
    assert.ok(fs.existsSync(lockFile), 'fresh index.lock must NOT be removed');
  });

  await test('removeStaleIndexLock preserves lock exactly at 300_000ms boundary', () => {
    const dir = createTmpDir();
    fs.mkdirSync(path.join(dir, '.git'), { recursive: true });
    const lockFile = path.join(dir, '.git', 'index.lock');
    fs.writeFileSync(lockFile, '');
    // Set mtime to exactly 300000ms ago (threshold is `age > 300000`, so equality does NOT remove)
    // Use a time just inside the threshold (age ~= 299_000ms)
    const recentTime = new Date(Date.now() - 299000);
    fs.utimesSync(lockFile, recentTime, recentTime);
    engine.removeStaleIndexLock(dir);
    assert.ok(fs.existsSync(lockFile), 'lock within threshold window must be preserved');
  });

  await test('removeStaleIndexLock swallows errors on bogus rootDir (no throw)', () => {
    // Pass a non-string value — path.join will throw inside, but the outer try/catch swallows it
    // Use a value that flows through path.join without crashing — statSync/unlinkSync path errors get caught
    const bogus = path.join(createTmpDir(), 'does', 'not', 'exist');
    // fs.existsSync on missing nested dir returns false → no-op, must not throw
    engine.removeStaleIndexLock(bogus);
  });

  // ── buildProjectContext ──

  const sampleProject = (name, extras = {}) => ({
    name,
    localPath: `/repos/${name}`,
    adoOrg: 'myorg',
    adoProject: 'myproject',
    repoName: `${name}-repo`,
    repositoryId: `GUID-${name}`,
    ...extras,
  });

  await test('buildProjectContext single-project mode (not fan-out) emits multi-project scope', () => {
    const projects = [sampleProject('alpha')];
    const out = engine.buildProjectContext(projects, projects[0], false, 'dallas', 'Engineer');
    assert.ok(out.includes('## Scope: Multi-project'), 'non-fan-out always shows multi-project scope header');
    assert.ok(out.includes('## Available Projects'), 'projects section must be present');
    assert.ok(out.includes('### alpha'), 'project name must be rendered');
    assert.ok(out.includes('/repos/alpha'), 'localPath must be rendered');
    assert.ok(out.includes('myorg/myproject/alpha-repo'), 'repo triple must be rendered');
    assert.ok(out.includes('GUID-alpha'), 'repositoryId must be rendered');
  });

  await test('buildProjectContext fan-out mode names the assigned project', () => {
    const projects = [sampleProject('alpha'), sampleProject('beta')];
    const out = engine.buildProjectContext(projects, projects[1], true, 'dallas', 'Engineer');
    assert.ok(out.includes('## Scope: Fan-out'), 'fan-out header must appear when isFanOut=true');
    assert.ok(out.includes('**beta**'), 'assigned project name must be bolded in fan-out copy');
    assert.ok(!out.includes('## Scope: Multi-project'), 'non-fan-out header must NOT appear');
    // Available Projects list still includes both
    assert.ok(out.includes('### alpha'));
    assert.ok(out.includes('### beta'));
  });

  await test('buildProjectContext fan-out without assignedProject falls back to multi-project scope', () => {
    const projects = [sampleProject('alpha')];
    const out = engine.buildProjectContext(projects, null, true, 'dallas', 'Engineer');
    // isFanOut=true but assignedProject falsy → condition `isFanOut && assignedProject` is false
    assert.ok(out.includes('## Scope: Multi-project'), 'missing assignedProject must fall back to multi-project');
    assert.ok(!out.includes('## Scope: Fan-out'), 'must not emit fan-out header without assignedProject');
  });

  await test('buildProjectContext empty projects array still emits the framing sections', () => {
    const out = engine.buildProjectContext([], null, false, 'dallas', 'Engineer');
    assert.ok(out.includes('## Scope: Multi-project'), 'scope header still present');
    assert.ok(out.includes('## Available Projects'), 'projects section header still present');
    // No project lines
    assert.ok(!out.includes('### '), 'no project lines for empty array');
  });

  await test('buildProjectContext renders "host:" label derived from repoHost', () => {
    const gh = sampleProject('ghrepo', { repoHost: 'github' });
    const ado = sampleProject('adorepo', { repoHost: 'ado' });
    const out = engine.buildProjectContext([gh, ado], gh, true, 'dallas', 'Engineer');
    assert.ok(/host: GitHub/.test(out), 'github repoHost must render "GitHub"');
    assert.ok(/host: Azure DevOps/.test(out), 'ado repoHost must render "Azure DevOps"');
  });

  await test('buildProjectContext renders "ID: unknown" when repositoryId missing', () => {
    const p = sampleProject('noid');
    delete p.repositoryId;
    const out = engine.buildProjectContext([p], p, false, 'dallas', 'Engineer');
    assert.ok(out.includes('ID: unknown'), 'missing repositoryId must fall back to "unknown"');
  });

  await test('buildProjectContext includes optional description line when present', () => {
    const p = sampleProject('docd', { description: 'Core orchestrator' });
    const out = engine.buildProjectContext([p], p, false, 'dallas', 'Engineer');
    assert.ok(out.includes('**What it is:** Core orchestrator'), 'description must be rendered');
  });

  await test('buildProjectContext omits description line when not set', () => {
    const p = sampleProject('nodocs');
    const out = engine.buildProjectContext([p], p, false, 'dallas', 'Engineer');
    assert.ok(!out.includes('**What it is:**'), 'description line must be absent when not set');
  });

  await test('buildProjectContext lists all projects in fan-out (other agents reference)', () => {
    const a = sampleProject('alpha');
    const b = sampleProject('beta');
    const c = sampleProject('gamma');
    const out = engine.buildProjectContext([a, b, c], b, true, 'dallas', 'Engineer');
    // Even though beta is assigned, all three appear in the list
    assert.ok(out.includes('### alpha'));
    assert.ok(out.includes('### beta'));
    assert.ok(out.includes('### gamma'));
  });

  // ── engine/projects.js: removeProject ──────────────────────────────────────

  function _setupProjectForRemoval({ projectName = 'demo', extraConfig = {} } = {}) {
    const restore = createTestMinionsDir();
    const dir = process.env.MINIONS_TEST_DIR;
    const projectDir = path.join(dir, 'projects', projectName);
    fs.mkdirSync(projectDir, { recursive: true });
    fs.writeFileSync(path.join(projectDir, 'work-items.json'), JSON.stringify([
      { id: 'P-pending', status: 'pending', project: projectName },
      { id: 'P-queued', status: 'queued', project: projectName },
      { id: 'P-done', status: 'done', project: projectName },
    ]));
    fs.writeFileSync(path.join(projectDir, 'pull-requests.json'), JSON.stringify([{ id: 'PR-1' }]));
    fs.writeFileSync(path.join(dir, 'config.json'), JSON.stringify({
      projects: [{ name: projectName, localPath: projectDir, repoHost: 'github' }],
      agents: {}, engine: {},
      ...extraConfig,
    }));
    delete require.cache[require.resolve('../engine/projects')];
    return { dir, projectDir, restore };
  }

  await test('removeProject returns ok=false when project not found', () => {
    const { restore } = _setupProjectForRemoval();
    try {
      const { removeProject } = require('../engine/projects');
      const r = removeProject('nonexistent');
      assert.strictEqual(r.ok, false);
      assert.ok(/No project linked/.test(r.error));
    } finally { restore(); }
  });

  await test('removeProject unlinks from config.json', () => {
    const { dir, restore } = _setupProjectForRemoval();
    try {
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo');
      assert.strictEqual(r.ok, true);
      assert.strictEqual(r.project.name, 'demo');
      const cfg = JSON.parse(fs.readFileSync(path.join(dir, 'config.json'), 'utf8'));
      assert.strictEqual(cfg.projects.length, 0);
    } finally { restore(); }
  });

  await test('removeProject finds project by localPath as well as by name', () => {
    const { projectDir, restore } = _setupProjectForRemoval();
    try {
      const { removeProject } = require('../engine/projects');
      const r = removeProject(projectDir);
      assert.strictEqual(r.ok, true);
      assert.strictEqual(r.project.name, 'demo');
    } finally { restore(); }
  });

  await test('removeProject cancels pending and queued work items but preserves done items', () => {
    const { dir, restore } = _setupProjectForRemoval();
    try {
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo');
      assert.strictEqual(r.cancelledItems, 2);
      // Data dir was archived — read from there
      const archiveDir = path.join(dir, 'projects', '.archived');
      const archived = fs.readdirSync(archiveDir).find(f => f.startsWith('demo-'));
      const wis = JSON.parse(fs.readFileSync(path.join(archiveDir, archived, 'work-items.json'), 'utf8'));
      const byId = Object.fromEntries(wis.map(w => [w.id, w]));
      assert.strictEqual(byId['P-pending'].status, 'cancelled');
      assert.strictEqual(byId['P-pending']._cancelledBy, 'project-removed');
      assert.strictEqual(byId['P-queued'].status, 'cancelled');
      assert.strictEqual(byId['P-done'].status, 'done');
    } finally { restore(); }
  });

  await test('removeProject drains pending dispatch entries for the project', () => {
    const { dir, restore } = _setupProjectForRemoval();
    try {
      const dispatchPath = path.join(dir, 'engine', 'dispatch.json');
      fs.writeFileSync(dispatchPath, JSON.stringify({
        pending: [
          { id: 'd1', meta: { item: { project: 'demo' } } },
          { id: 'd2', meta: { item: { project: 'other' } } },
        ],
        active: [],
        completed: [],
      }));
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo');
      assert.strictEqual(r.drainedDispatches, 1);
      const dispatch = JSON.parse(fs.readFileSync(dispatchPath, 'utf8'));
      assert.strictEqual(dispatch.pending.length, 1);
      assert.strictEqual(dispatch.pending[0].id, 'd2');
    } finally { restore(); }
  });

  await test('removeProject disables schedules targeting this project but leaves "any" alone', () => {
    const { dir, restore } = _setupProjectForRemoval({
      extraConfig: {
        schedules: [
          { id: 's1', project: 'demo', enabled: true },
          { id: 's2', project: 'other', enabled: true },
          { id: 's3', enabled: true },
        ],
      },
    });
    try {
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo');
      assert.strictEqual(r.disabledSchedules, 1);
      const cfg = JSON.parse(fs.readFileSync(path.join(dir, 'config.json'), 'utf8'));
      const byId = Object.fromEntries(cfg.schedules.map(s => [s.id, s]));
      assert.strictEqual(byId.s1.enabled, false);
      assert.strictEqual(byId.s2.enabled, true);
      assert.strictEqual(byId.s3.enabled, true);
    } finally { restore(); }
  });

  await test('removeProject archives projects/<name>/ to projects/.archived/<name>-YYYYMMDD/', () => {
    const { dir, projectDir, restore } = _setupProjectForRemoval();
    try {
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo');
      assert.ok(r.archivedTo, 'archivedTo must be set');
      assert.ok(r.archivedTo.startsWith('projects/.archived/demo-'), 'expected projects/.archived/demo-*: ' + r.archivedTo);
      assert.ok(!fs.existsSync(projectDir), 'original data dir should be moved');
      assert.ok(fs.existsSync(path.join(dir, r.archivedTo, 'work-items.json')));
    } finally { restore(); }
  });

  await test('removeProject with keepData leaves data dir in place', () => {
    const { projectDir, restore } = _setupProjectForRemoval();
    try {
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo', { keepData: true });
      assert.strictEqual(r.archivedTo, null);
      assert.strictEqual(r.purgedDataDir, false);
      assert.ok(fs.existsSync(projectDir), 'data dir should remain when keepData is set');
    } finally { restore(); }
  });

  await test('removeProject with purge deletes data dir entirely', () => {
    const { dir, projectDir, restore } = _setupProjectForRemoval();
    try {
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo', { purge: true });
      assert.strictEqual(r.purgedDataDir, true);
      assert.strictEqual(r.archivedTo, null);
      assert.ok(!fs.existsSync(projectDir));
      assert.ok(!fs.existsSync(path.join(dir, 'projects', '.archived')), 'no archive should be created on purge');
    } finally { restore(); }
  });

  await test('removeProject disambiguates same-day archive directories', () => {
    const { dir, restore } = _setupProjectForRemoval();
    try {
      // Pre-seed an existing archive entry to force the suffix branch
      const archiveRoot = path.join(dir, 'projects', '.archived');
      fs.mkdirSync(archiveRoot, { recursive: true });
      const stamp = new Date().toISOString().slice(0, 10).replace(/-/g, '');
      fs.mkdirSync(path.join(archiveRoot, 'demo-' + stamp), { recursive: true });
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo');
      assert.ok(/-2$/.test(r.archivedTo), 'expected -2 suffix on collision: ' + r.archivedTo);
    } finally { restore(); }
  });

  await test('removeProject drains active dispatch entries (agent kill path)', () => {
    const { dir, restore } = _setupProjectForRemoval();
    try {
      const dispatchPath = path.join(dir, 'engine', 'dispatch.json');
      fs.writeFileSync(dispatchPath, JSON.stringify({
        pending: [],
        // No real PID file → cleanDispatchEntries skips kill but still drains the entry
        active: [{ id: 'd-active', agent: 'dallas', meta: { item: { project: 'demo' } } }],
        completed: [],
      }));
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo');
      assert.strictEqual(r.drainedDispatches, 1);
      const dispatch = JSON.parse(fs.readFileSync(dispatchPath, 'utf8'));
      assert.strictEqual(dispatch.active.length, 0);
    } finally { restore(); }
  });

  await test('cleanDispatchEntries unlinks PID file from engine/tmp/ (the path spawn-agent.js writes to)', () => {
    // Regression guard: spawn-agent.js writes pid files to engine/tmp/pid-<id>.pid
    // (see engine/spawn-agent.js:220, derived from the prompt-file path that
    // engine.js builds in engine/tmp/). cleanDispatchEntries previously read
    // the pid from engine/pid-<id>.pid — wrong directory — so on `minions remove`
    // and plan delete the live pid file was never deleted and the tracked PID
    // was never killed. Surviving agents kept writing to a worktree the engine
    // had already torn down.
    const restore = createTestMinionsDir();
    const dir = process.env.MINIONS_TEST_DIR;
    try {
      const tmpDir = path.join(dir, 'engine', 'tmp');
      fs.mkdirSync(tmpDir, { recursive: true });
      const dispatchId = 'd-cleantest';
      const realPidPath = path.join(tmpDir, `pid-${dispatchId}.pid`);
      fs.writeFileSync(realPidPath, '99999999'); // bogus PID — kill is a no-op, file deletion is what we assert

      // Decoy at the BUGGY path so the test fails clearly when the function
      // unlinks the wrong location instead of the right one.
      const buggyPidPath = path.join(dir, 'engine', `pid-${dispatchId}.pid`);
      fs.writeFileSync(buggyPidPath, '99999999');

      fs.writeFileSync(path.join(dir, 'engine', 'dispatch.json'), JSON.stringify({
        pending: [],
        active: [{ id: dispatchId, agent: 'dallas' }],
        completed: [],
      }));

      delete require.cache[require.resolve('../engine/dispatch')];
      const { cleanDispatchEntries } = require('../engine/dispatch');
      const removed = cleanDispatchEntries(d => d.id === dispatchId);

      assert.strictEqual(removed, 1, 'cleanDispatchEntries should drain the matching active entry');
      assert.ok(!fs.existsSync(realPidPath),
        'pid file at engine/tmp/pid-<id>.pid must be unlinked — that is where spawn-agent.js writes it');
    } finally { restore(); }
  });

  await test('minions kill scans engine/tmp/ for pid files (not engine/)', () => {
    // Companion bug: the `minions kill` CLI handler also scanned the wrong
    // directory, so on Windows/Linux alike the command cleared the dispatch
    // queue but never reaped the agent processes. The PID files live in
    // engine/tmp/ — same place spawn-agent.js writes them.
    const src = fs.readFileSync(path.join(MINIONS_DIR, 'engine', 'cli.js'), 'utf8');
    const killStart = src.indexOf('  kill()');
    assert.ok(killStart > 0, 'kill handler must exist in engine/cli.js');
    const killEnd = src.indexOf('\n  },', killStart);
    const block = src.slice(killStart, killEnd > -1 ? killEnd : killStart + 4000);

    assert.ok(/(?:readdirSync|safeReadDir)\([^)]*ENGINE_DIR\s*,\s*['"]tmp['"]/.test(block) ||
              /(?:readdirSync|safeReadDir)\(\s*pidDir\s*\)/.test(block),
      'kill must scan engine/tmp/ (extracted to a pidDir variable is fine, safeReadDir wrapper is also fine) — pid files live there per spawn-agent.js');

    // Also: never call process.kill with a falsy / NaN pid. Empty pid files
    // would resolve to Number('') === 0, and process.kill(0) on POSIX targets
    // the entire caller process group. Guard before the kill.
    assert.ok(/(?:Number\(pid\)|safePid|pidNum)\s*[>!]/.test(block) ||
              /if\s*\(\s*!?(?:pid|pidNum|safePid)/.test(block),
      'kill must guard against falsy/zero PIDs before calling process.kill');
  });

  await test('removeProject archives PRD JSONs whose project field matches', () => {
    const { dir, restore } = _setupProjectForRemoval();
    try {
      // Drop a PRD that targets demo
      const prdPath = path.join(dir, 'prd', 'demo-2026-04-27.json');
      fs.writeFileSync(prdPath, JSON.stringify({ project: 'demo', source_plan: 'demo-plan.md', missing_features: [] }));
      // And a PRD that targets a different project — should NOT be archived
      fs.writeFileSync(path.join(dir, 'prd', 'other-2026-04-27.json'), JSON.stringify({ project: 'other', missing_features: [] }));
      // Drop a source .md that the demo PRD references
      fs.writeFileSync(path.join(dir, 'plans', 'demo-plan.md'), '# Demo plan');
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo');
      assert.ok(r.archivedPlans.includes('prd/demo-2026-04-27.json'), 'PRD should be archived: ' + JSON.stringify(r.archivedPlans));
      assert.ok(!fs.existsSync(prdPath), 'PRD should be moved out of prd/');
      assert.ok(fs.existsSync(path.join(dir, 'prd', 'archive', 'demo-2026-04-27.json')), 'PRD should land in prd/archive/');
      assert.ok(fs.existsSync(path.join(dir, 'plans', 'archive', 'demo-plan.md')), 'linked source plan should also be archived');
      assert.ok(fs.existsSync(path.join(dir, 'prd', 'other-2026-04-27.json')), 'unrelated PRD should remain');
    } finally { restore(); }
  });

  await test('removeProject archives plan .md whose content has Project: <name>', () => {
    const { dir, restore } = _setupProjectForRemoval();
    try {
      fs.writeFileSync(path.join(dir, 'plans', 'unrelated.md'), '# A plan with no project field');
      fs.writeFileSync(path.join(dir, 'plans', 'tagged.md'), '# Tagged\n\n**Project:** demo\n\n## Stuff');
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo');
      assert.ok(r.archivedPlans.includes('plans/tagged.md'), 'plan with Project: line should be archived: ' + JSON.stringify(r.archivedPlans));
      assert.ok(!r.archivedPlans.includes('plans/unrelated.md'), 'plan without project hint should NOT be archived');
      assert.ok(fs.existsSync(path.join(dir, 'plans', 'archive', 'tagged.md')));
      assert.ok(fs.existsSync(path.join(dir, 'plans', 'unrelated.md')));
    } finally { restore(); }
  });

  await test('removeProject archives plan .md by filename match (catches plans missing Project: line)', () => {
    const { dir, restore } = _setupProjectForRemoval();
    try {
      // The exact case that bit us in production: a plan tied to a project but
      // with no `Project:` line in the body. Filename should still catch it.
      fs.writeFileSync(path.join(dir, 'plans', 'demo-roadmap.md'), '# A plan with no project field, but filename mentions demo');
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo');
      assert.ok(r.archivedPlans.includes('plans/demo-roadmap.md'), 'filename match should archive: ' + JSON.stringify(r.archivedPlans));
    } finally { restore(); }
  });

  await test('removeProject surfaces pipelineRefs for pipelines monitoring this project', () => {
    const { dir, restore } = _setupProjectForRemoval();
    try {
      // Stub out pipeline.getPipelines via require.cache injection
      const stubPath = require.resolve('../engine/pipeline');
      require.cache[stubPath] = { exports: {
        getPipelines: () => [
          { id: 'pl-watching', monitoredResources: [{ project: 'demo' }] },
          { id: 'pl-other', monitoredResources: [{ project: 'other' }] },
          { id: 'pl-stage-watching', stages: [{ monitoredResources: [{ _project: 'demo' }] }] },
        ],
      } };
      delete require.cache[require.resolve('../engine/projects')];
      const { removeProject } = require('../engine/projects');
      const r = removeProject('demo');
      assert.deepStrictEqual(r.pipelineRefs.sort(), ['pl-stage-watching', 'pl-watching']);
    } finally {
      delete require.cache[require.resolve('../engine/pipeline')];
      restore();
    }
  });
}

// ─── P-2a6d9c4f: engine.js spawnAgent runtime wiring ─────────────────────────

async function testEngineRuntimeWiring() {
  console.log('\n── engine.js — Runtime Adapter Wiring (P-2a6d9c4f) ──');

  const engine = require(path.join(MINIONS_DIR, 'engine.js'));
  const claude = require(path.join(MINIONS_DIR, 'engine', 'runtimes', 'claude'));
  const copilot = require(path.join(MINIONS_DIR, 'engine', 'runtimes', 'copilot'));

  // ── _buildAgentSpawnFlags: shape ─────────────────────────────────────────

  await test('_buildAgentSpawnFlags exists and returns string[]', () => {
    assert.strictEqual(typeof engine._buildAgentSpawnFlags, 'function');
    const out = engine._buildAgentSpawnFlags(claude, {});
    assert.ok(Array.isArray(out));
    for (const s of out) assert.strictEqual(typeof s, 'string', `non-string in flags: ${s}`);
  });

  await test('_buildAgentSpawnFlags always emits --runtime <name> as the first pair', () => {
    const flags = engine._buildAgentSpawnFlags(claude, {});
    assert.strictEqual(flags[0], '--runtime');
    assert.strictEqual(flags[1], 'claude');

    const flagsCopilot = engine._buildAgentSpawnFlags(copilot, {});
    assert.strictEqual(flagsCopilot[0], '--runtime');
    assert.strictEqual(flagsCopilot[1], 'copilot');
  });

  // ── Always-applicable opts ───────────────────────────────────────────────

  await test('_buildAgentSpawnFlags emits --max-turns/--model/--allowedTools when set', () => {
    const flags = engine._buildAgentSpawnFlags(claude, {
      maxTurns: 100,
      model: 'sonnet',
      allowedTools: 'Read,Edit',
    });
    const mt = flags.indexOf('--max-turns');
    assert.ok(mt >= 0 && flags[mt + 1] === '100');
    const m = flags.indexOf('--model');
    assert.ok(m >= 0 && flags[m + 1] === 'sonnet');
    const at = flags.indexOf('--allowedTools');
    assert.ok(at >= 0 && flags[at + 1] === 'Read,Edit');
  });

  await test('_buildAgentSpawnFlags omits --model when undefined (let runtime pick its own)', () => {
    const flags = engine._buildAgentSpawnFlags(claude, { model: undefined });
    assert.ok(!flags.includes('--model'));
  });

  await test('_buildAgentSpawnFlags omits --allowedTools when null/empty', () => {
    assert.ok(!engine._buildAgentSpawnFlags(claude, { allowedTools: null }).includes('--allowedTools'));
    assert.ok(!engine._buildAgentSpawnFlags(claude, { allowedTools: '' }).includes('--allowedTools'));
    assert.ok(!engine._buildAgentSpawnFlags(claude, {}).includes('--allowedTools'));
  });

  // ── effort: gated on capabilities.effortLevels ────────────────────────────

  await test('_buildAgentSpawnFlags emits --effort when capability is true', () => {
    const flags = engine._buildAgentSpawnFlags(claude, { effort: 'low' });
    const i = flags.indexOf('--effort');
    assert.ok(i >= 0 && flags[i + 1] === 'low');
  });

  await test('_buildAgentSpawnFlags omits --effort when capability is false', () => {
    const fakeNoEffort = { name: 'no-effort', capabilities: { ...claude.capabilities, effortLevels: false } };
    const flags = engine._buildAgentSpawnFlags(fakeNoEffort, { effort: 'low' });
    assert.ok(!flags.includes('--effort'));
  });

  await test('_buildAgentSpawnFlags omits --effort when opt is null/undefined even if capability is true', () => {
    assert.ok(!engine._buildAgentSpawnFlags(claude, { effort: null }).includes('--effort'));
    assert.ok(!engine._buildAgentSpawnFlags(claude, {}).includes('--effort'));
  });

  // ── sessionId: gated on capabilities.sessionResume ────────────────────────

  await test('_buildAgentSpawnFlags emits --resume <id> when capability true and sessionId set', () => {
    const flags = engine._buildAgentSpawnFlags(claude, { sessionId: 'sess-abc' });
    const i = flags.indexOf('--resume');
    assert.ok(i >= 0 && flags[i + 1] === 'sess-abc');
  });

  await test('_buildAgentSpawnFlags omits --resume when capability is false (even if opt set)', () => {
    const fakeNoResume = { name: 'no-resume', capabilities: { ...claude.capabilities, sessionResume: false } };
    const flags = engine._buildAgentSpawnFlags(fakeNoResume, { sessionId: 'sess-abc' });
    assert.ok(!flags.includes('--resume'));
  });

  // ── maxBudget: gated on capabilities.budgetCap ────────────────────────────

  await test('_buildAgentSpawnFlags emits --max-budget-usd when capability true', () => {
    const flags = engine._buildAgentSpawnFlags(claude, { maxBudget: 5 });
    const i = flags.indexOf('--max-budget-usd');
    assert.ok(i >= 0 && flags[i + 1] === '5');
  });

  await test('_buildAgentSpawnFlags honors maxBudget=0 (??-equivalent)', () => {
    const flags = engine._buildAgentSpawnFlags(claude, { maxBudget: 0 });
    const i = flags.indexOf('--max-budget-usd');
    assert.ok(i >= 0 && flags[i + 1] === '0', `0 must be a valid cap: ${flags.join(' ')}`);
  });

  await test('_buildAgentSpawnFlags omits --max-budget-usd when capability is false (Copilot)', () => {
    const flags = engine._buildAgentSpawnFlags(copilot, { maxBudget: 5 });
    assert.ok(!flags.includes('--max-budget-usd'),
      `Copilot capabilities.budgetCap=false; --max-budget-usd must NOT appear: ${flags.join(' ')}`);
  });

  // ── bare: gated on capabilities.bareMode ──────────────────────────────────

  await test('_buildAgentSpawnFlags emits --bare only when bare===true AND capability true', () => {
    assert.ok(engine._buildAgentSpawnFlags(claude, { bare: true }).includes('--bare'));
    assert.ok(!engine._buildAgentSpawnFlags(claude, { bare: false }).includes('--bare'));
    assert.ok(!engine._buildAgentSpawnFlags(claude, {}).includes('--bare'));
    // Capability-false runtime — bare opt ignored
    assert.ok(!engine._buildAgentSpawnFlags(copilot, { bare: true }).includes('--bare'),
      'Copilot capabilities.bareMode=false; --bare must NOT appear');
  });

  // ── fallbackModel: gated on capabilities.fallbackModel ────────────────────

  await test('_buildAgentSpawnFlags emits --fallback-model when capability true', () => {
    const flags = engine._buildAgentSpawnFlags(claude, { fallbackModel: 'haiku' });
    const i = flags.indexOf('--fallback-model');
    assert.ok(i >= 0 && flags[i + 1] === 'haiku');
  });

  await test('_buildAgentSpawnFlags omits --fallback-model when capability is false (Copilot)', () => {
    const flags = engine._buildAgentSpawnFlags(copilot, { fallbackModel: 'gpt-4o' });
    assert.ok(!flags.includes('--fallback-model'));
  });

  // ── Copilot-specific opts: emitted unconditionally; adapter ignores ──────

  await test('_buildAgentSpawnFlags forwards --stream <on|off> when set', () => {
    const flags = engine._buildAgentSpawnFlags(copilot, { stream: 'on' });
    const i = flags.indexOf('--stream');
    assert.ok(i >= 0 && flags[i + 1] === 'on');

    const off = engine._buildAgentSpawnFlags(copilot, { stream: 'off' });
    const j = off.indexOf('--stream');
    assert.ok(j >= 0 && off[j + 1] === 'off');
  });

  await test('_buildAgentSpawnFlags omits --stream when null/empty', () => {
    assert.ok(!engine._buildAgentSpawnFlags(copilot, { stream: null }).includes('--stream'));
    assert.ok(!engine._buildAgentSpawnFlags(copilot, { stream: '' }).includes('--stream'));
    assert.ok(!engine._buildAgentSpawnFlags(copilot, {}).includes('--stream'));
  });

  await test('_buildAgentSpawnFlags forwards --disable-builtin-mcps / --no-custom-instructions / --enable-reasoning-summaries when true', () => {
    const flags = engine._buildAgentSpawnFlags(copilot, {
      disableBuiltinMcps: true,
      suppressAgentsMd: true,
      reasoningSummaries: true,
    });
    assert.ok(flags.includes('--disable-builtin-mcps'));
    assert.ok(flags.includes('--no-custom-instructions'));
    assert.ok(flags.includes('--enable-reasoning-summaries'));
  });

  await test('_buildAgentSpawnFlags omits Copilot bool flags when false/missing', () => {
    const flags = engine._buildAgentSpawnFlags(copilot, {
      disableBuiltinMcps: false,
      suppressAgentsMd: false,
      reasoningSummaries: false,
    });
    assert.ok(!flags.includes('--disable-builtin-mcps'));
    assert.ok(!flags.includes('--no-custom-instructions'));
    assert.ok(!flags.includes('--enable-reasoning-summaries'));
    const flags2 = engine._buildAgentSpawnFlags(copilot, {});
    assert.ok(!flags2.includes('--disable-builtin-mcps'));
    assert.ok(!flags2.includes('--no-custom-instructions'));
    assert.ok(!flags2.includes('--enable-reasoning-summaries'));
  });

  // ── End-to-end: Claude regression via spawn-agent.parseSpawnArgs ──────────

  await test('Claude end-to-end: engine flags → spawn-agent.parseSpawnArgs → adapter buildArgs round-trip', () => {
    // The integration contract of P-2a6d9c4f: every opt that engine.js threads
    // through must round-trip cleanly through spawn-agent's argv parser into
    // runtime.buildArgs(opts) without loss or duplication.
    const spawnAgent = require(path.join(MINIONS_DIR, 'engine', 'spawn-agent'));
    const flags = engine._buildAgentSpawnFlags(claude, {
      maxTurns: 50,
      model: 'sonnet',
      allowedTools: 'Read,Edit,Bash',
      effort: 'low',
      sessionId: 'sess-roundtrip',
      maxBudget: 0,           // ← 0 must survive the round-trip
      bare: true,
      fallbackModel: 'haiku',
    });
    const argv = ['node', 'spawn-agent.js', '/p', '/s', ...flags];
    const parsed = spawnAgent.parseSpawnArgs(argv);
    assert.strictEqual(parsed.runtimeName, 'claude');
    assert.deepStrictEqual(parsed.passthrough, [], 'engine flags must all be recognized by spawn-agent — no passthrough');
    assert.strictEqual(parsed.opts.maxTurns, '50');
    assert.strictEqual(parsed.opts.model, 'sonnet');
    assert.strictEqual(parsed.opts.allowedTools, 'Read,Edit,Bash');
    assert.strictEqual(parsed.opts.effort, 'low');
    assert.strictEqual(parsed.opts.sessionId, 'sess-roundtrip');
    assert.strictEqual(parsed.opts.maxBudget, '0', '0 must survive parsing — string form is fine, adapter coerces');
    assert.strictEqual(parsed.opts.bare, true);
    assert.strictEqual(parsed.opts.fallbackModel, 'haiku');
  });

  await test('Copilot end-to-end: capability gates strip Claude-only opts before spawn-agent', () => {
    const flags = engine._buildAgentSpawnFlags(copilot, {
      model: 'claude-sonnet-4',
      maxBudget: 5,            // budgetCap=false → MUST NOT appear
      bare: true,              // bareMode=false → MUST NOT appear
      fallbackModel: 'haiku',  // fallbackModel=false → MUST NOT appear
      stream: 'on',
      disableBuiltinMcps: true,
      suppressAgentsMd: true,
      effort: 'medium',
    });
    assert.ok(!flags.includes('--max-budget-usd'));
    assert.ok(!flags.includes('--bare'));
    assert.ok(!flags.includes('--fallback-model'));
    assert.ok(flags.includes('--stream'));
    assert.ok(flags.includes('--disable-builtin-mcps'));
    assert.ok(flags.includes('--no-custom-instructions'));
    assert.ok(flags.includes('--effort'));
  });

  // ── Source guard: engine.js has zero `runtime.name === ...` branches ─────

  await test('engine.js source contains zero `runtime.name ===` (or ==) branches — capability flags only', () => {
    const src = fs.readFileSync(path.join(MINIONS_DIR, 'engine.js'), 'utf8');
    const codeOnly = src
      .replace(/\/\*[\s\S]*?\*\//g, '')         // block comments
      .replace(/(^|[^:])\/\/[^\n]*/g, '$1')     // line comments
      .replace(/'[^'\n]*'/g, "''")
      .replace(/"[^"\n]*"/g, '""')
      .replace(/`[^`]*`/g, '``');
    const banned = /\bruntime\.name\s*={2,3}\s*/;
    assert.ok(!banned.test(codeOnly),
      `engine.js still branches on runtime.name; capability flags only. Match: ${(codeOnly.match(banned) || [''])[0]}`);
  });

  // ── Source guard: spawnAgent reads via shared.resolveAgent* helpers ──────

  await test('engine.js spawnAgent invokes shared.resolveAgentCli/Model/MaxBudget/BareMode', () => {
    const src = fs.readFileSync(path.join(MINIONS_DIR, 'engine.js'), 'utf8');
    // Normalize whitespace so the assertions don't break on cosmetic edits
    const compact = src.replace(/\s+/g, ' ');
    for (const helper of ['resolveAgentCli', 'resolveAgentModel', 'resolveAgentMaxBudget', 'resolveAgentBareMode']) {
      assert.ok(compact.includes(`shared.${helper}(`),
        `engine.js spawnAgent must call shared.${helper}(...) — never read agent.cli/model/etc directly`);
    }
    assert.ok(compact.includes('resolveRuntime('),
      'engine.js must resolve the runtime via the registry, not require the adapter directly');
  });

  await test('engine.js no longer reads claudeConfig.permissionMode (legacy) inside spawn paths', () => {
    const src = fs.readFileSync(path.join(MINIONS_DIR, 'engine.js'), 'utf8');
    const codeOnly = src
      .replace(/\/\*[\s\S]*?\*\//g, '')
      .replace(/(^|[^:])\/\/[^\n]*/g, '$1')
      .replace(/'[^'\n]*'/g, "''")
      .replace(/"[^"\n]*"/g, '""');
    assert.ok(!/claudeConfig[?]?\.permissionMode/.test(codeOnly),
      'engine.js code body must not read the deprecated claudeConfig.permissionMode field — adapter owns the permission flag');
  });
}

main()
  .then(code => {
    restorePreservedLiveLog();
    process.exit(code);
  })
  .catch(e => {
    restorePreservedLiveLog();
    console.error(e);
    process.exit(1);
  });
